import requests

def get_vm_prices(sku_name: str, region: str, os_family: str = "Linux"):
    """Fetch PAYG and reservation prices for a VM SKU from the Retail Prices API."""
    url = "https://prices.azure.com/api/retail/prices"
    base_filter = (
        f"serviceName eq 'Virtual Machines' "
        f"and skuName eq '{sku_name}' "
        f"and armRegionName eq '{region}' "
        f"and contains(productName, '{os_family}')"
    )

    results = {}
    for price_type in ("Consumption", "Reservation"):
        params = {
            "api-version": "2023-01-01-preview",
            "$filter": f"{base_filter} and priceType eq '{price_type}' and not contains(skuName, 'Spot') and not contains(skuName, 'Low Priority')",
        }
        resp = requests.get(url, params=params, timeout=10)
        items = resp.json().get("Items", [])
        for item in items:
            label = f"{price_type}:{item.get('meterName','')}"
            results[label] = item.get("retailPrice", 0)

    return results

prices = get_vm_prices("D4s v5", "eastus", "Linux")
for label, price in sorted(prices.items()):
    print(f"  {label}: ${price:.4f}/hr")
